INSERT INTO `admin_accounts` (`id`, `created_at`, `password_hash`, `updated_at`, `username`, `role`, `display_name`) VALUES (1,'2026-05-15 17:09:53.799000','{bcrypt}$2a$10$nOxz0pOoUKpNCAuAqfb/4.Z5C0nxcoXS1MbinCJI92mlDQ3473i66','2026-05-15 17:09:53.799000','sysadmin','系统管理员','系统管理员'),(2,'2026-05-15 17:09:53.955000','{bcrypt}$2a$10$MyTM8199szarwzRHM3QNZOkX8.ChvaWXDKoRawGm607glegRX2sR2','2026-05-15 17:09:53.955000','mwadmin','中间件管理岗','中间件管理员'),(3,'2026-05-15 17:09:54.079000','{bcrypt}$2a$10$hl3PVpYZv4dutdfdqItbduTVMVshon4ZCgebnb395bQAqPwoIIxmO','2026-05-15 17:09:54.079000','dbadmin','数据库管理岗','数据库管理员'),(4,'2026-05-15 17:09:54.204000','{bcrypt}$2a$10$0GI29aXyvCRsXXj313LyMehp9wN8ByMRN7FlDdm8nysiXFTrk3WYy','2026-05-15 17:09:54.204000','hostadmin','主机管理岗','主机管理员'),(5,'2026-05-15 17:09:54.322000','{bcrypt}$2a$10$Ff7g8p4Be5TvZGNg9K4t4eK6COHEMZpL55pksidO1VKnhUZWWmzH.','2026-05-15 17:09:54.322000','netadmin','网络管理岗','网络管理员'),(6,'2026-05-15 17:09:54.442000','{bcrypt}$2a$10$ccjKX/z3Gi9aIw7ZeTzZvejcguBhL.bFVdPZNq98fhdyotmP6Rryu','2026-05-15 17:09:54.442000','secadmin','网络安全岗','安全管理员'),(7,'2026-05-15 17:09:54.567000','{bcrypt}$2a$10$h0RUtHsHvMjdscppnvDC0..NTQVFKMWMJSrTZGJ0Hpe0iB.I276/u','2026-05-15 17:09:54.567000','devmgr','开发经理','开发经理'),(8,'2026-05-15 17:09:54.685000','{bcrypt}$2a$10$HvvFHtAdXXJUlC4t2kgkE.m2GR2WHRN4SffhhYl18n/qA4Ohx2NfS','2026-05-15 17:09:54.685000','opsmgr','运维经理','运维经理');
