INSERT INTO `middleware_commands` (`id`, `software_type_id`, `name`, `command`, `brief_description`, `categories`, `command_format`, `detailed_description`, `description`, `sort_order`, `created_at`, `updated_at`) VALUES (1,15,'查看所有主题','kafka-topics.sh --list --bootstrap-server localhost:9092','查看所有主题','[\"查询\"]','kafka-topics.sh --list --bootstrap-server localhost:9092','列出Kafka集群中的所有topic',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(2,15,'创建主题','kafka-topics.sh --create --topic test --bootstrap-server localhost:9092 --partitions 3 --replication-factor 1','创建主题','[\"操作\", \"创建\"]','kafka-topics.sh --create --topic test --bootstrap-server localhost:9092 --partitions 3 --replication-factor 1','创建一个名为test的topic，包含3个分区',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(3,15,'生产消息','kafka-console-producer.sh --bootstrap-server localhost:9092 --topic test','生产消息','[\"生产\"]','kafka-console-producer.sh --bootstrap-server localhost:9092 --topic test','启动生产者，向test topic发送消息',NULL,2,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(4,15,'消费消息','kafka-console-consumer.sh --bootstrap-server localhost:9092 --topic test --from-beginning','消费消息','[\"消费\"]','kafka-console-consumer.sh --bootstrap-server localhost:9092 --topic test --from-beginning','启动消费者，从test topic消费消息',NULL,3,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(5,16,'查看Zookeeper状态','echo stat | nc localhost 2181','查看Zookeeper状态','[\"基础\", \"常用\", \"监控\"]','echo stat | nc localhost 2181','通过netcat连接Zookeeper并查看状态',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(6,16,'连接Zookeeper客户端','zkCli.sh -server localhost:2181','连接Zookeeper客户端','[\"基础\", \"常用\"]','zkCli.sh -server localhost:2181','启动Zookeeper命令行客户端',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(7,16,'查看根节点','ls /','查看根节点','[\"查询\"]','ls /','列出根目录下的所有子节点',NULL,2,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(8,16,'获取节点数据','get /path','获取节点数据','[\"查询\"]','get /path','获取指定路径节点的数据和状态',NULL,3,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(9,17,'查看所有队列','rabbitmqctl list_queues','查看所有队列','[\"查询\"]','rabbitmqctl list_queues','列出RabbitMQ中所有的队列及其消息数量',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(10,17,'查看所有交换机','rabbitmqctl list_exchanges','查看所有交换机','[\"查询\"]','rabbitmqctl list_exchanges','列出RabbitMQ中所有的交换机',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(11,17,'查看所有连接','rabbitmqctl list_connections','查看所有连接','[\"查询\"]','rabbitmqctl list_connections','列出当前所有的客户端连接',NULL,2,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(12,18,'查看集群信息','mqadmin clusterList -n localhost:9876','查看集群信息','[\"查询\"]','mqadmin clusterList -n localhost:9876','查看RocketMQ集群的详细信息',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(13,18,'查看所有主题','mqadmin topicList -n localhost:9876','查看所有主题','[\"查询\"]','mqadmin topicList -n localhost:9876','列出RocketMQ中的所有topic',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(14,18,'启动NameServer','sh mqnamesrv','启动NameServer','[\"启动\"]','sh mqnamesrv','启动RocketMQ的NameServer服务',NULL,2,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(15,19,'查看运行中的容器','docker ps','查看运行中的容器','[\"基础\", \"常用\", \"查询\"]','docker ps','列出当前正在运行的Docker容器',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(16,19,'查看所有容器','docker ps -a','查看所有容器','[\"查询\"]','docker ps -a','列出所有的Docker容器，包括停止的',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(17,19,'启动容器','docker start container_id','启动容器','[\"基础\", \"常用\", \"操作\"]','docker start container_id','启动指定ID的容器',NULL,2,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(18,19,'停止容器','docker stop container_id','停止容器','[\"基础\", \"常用\", \"操作\"]','docker stop container_id','停止指定ID的容器',NULL,3,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(19,19,'查看容器日志','docker logs container_id','查看容器日志','[\"基础\", \"常用\", \"日志\"]','docker logs container_id','查看指定容器的日志输出',NULL,4,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(20,19,'进入容器','docker exec -it container_id bash','进入容器','[\"基础\", \"常用\", \"操作\"]','docker exec -it container_id bash','以交互模式进入容器的bash shell',NULL,5,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(21,1,'【查看基础信息】redis-cli -a abc@123 -h 127.0.0.1  -p 6379 info','redis-cli -a $PASSWORD -h $HOST -p $PORT info','【查看基础信息】redis-cli -a abc@123 -h 127.0.0.1  -p 6379 info','[\"基础\", \"常用\", \"查询\"]','redis-cli -a $PASSWORD -h $HOST -p $PORT info','Redis Info 命令以一种易于理解和阅读的格式，返回关于 Redis 服务器的各种信息和统计数值。\n通过给定可选的参数 section ，可以让命令只返回某一部分的信息：\n1. Server (服务器信息)\n这部分记录了 Redis 守护进程自身的环境信息，通常是静态或变化缓慢的数据。\n\nredis_version: Redis 服务器的版本号。这是判断功能兼容性的重要依据。\n\nredis_git_sha1: 如果是从 Git 源码编译的，这里会显示 Git SHA1。通常为 00000000 表示非 Git 构建。\n\nredis_git_dirty: Git 工作目录是否包含未提交的修改（1 表示有修改）。\n\nos: 宿主操作系统的类型和内核版本。\n\narch_bits: 系统架构，64 位或 32 位。\n\nprocess_id: Redis 服务器进程的 PID。\n\nrun_id: 本次 Redis 启动时生成的随机标识符。它在集群和复制中用于唯一标识一个实例。\n\ntcp_port: Redis 监听的 TCP 端口。\n\nuptime_in_seconds / uptime_in_days: 自服务器启动以来已运行的时间（秒/天）。如果服务器经常重启，这个值会比较小。\n\nconfig_file: 当前使用的配置文件路径。\n\n2. Clients (客户端连接)\n这部分展示了所有连接到 Redis 的客户端信息。\n\nconnected_clients: 当前已连接的客户端数量。不包括通过从服务器（Slave）建立的内部连接。这个值过高可能意味着连接池配置不合理或存在连接泄露。\n\ncluster_connections: 集群总线占用的连接数近似值。\n\nmaxclients: 配置文件中设置的 maxclients 值，即允许同时连接的最大客户端数量。\n\nblocked_clients: 正在等待阻塞命令（如 BLPOP、BRPOP）的客户端数量。如果这个值持续很高，可能意味着有慢消费者或队列堆积。\n\ntracking_clients: 启用了客户端缓存的客户端数量 (Redis 7.0+ 特性)。\n\nclient_recent_max_input_buffer: 当前所有客户端连接中，最大的输入缓冲区大小。过大的输入缓冲区可能意味着有 key 过大或命令不当。\n\n3. Memory (内存信息)\n这是运维监控中最关键的模块，直接关系到 Redis 的稳定性和性能。\n\nused_memory: 由 Redis 内存分配器（如 jemalloc）分配的总字节数。这是 Redis 存储数据实际占用的逻辑内存。\n\nused_memory_human: 上一条数据的可读格式（如 1.8G）。\n\nused_memory_rss: 从操作系统角度看到的、分配给 Redis 的物理内存大小（常驻集大小），也就是 top/ps 命令看到的值。\n\nused_memory_peak: 历史内存消耗峰值（字节）。\n\nmaxmemory: 实例配置的最大可用内存上限。如果为 0，表示在 64 位系统上无限制。\n\nmaxmemory_policy: 当内存达到 maxmemory 上限时的淘汰策略（如 volatile-lru、allkeys-lru）。\n\nmem_fragmentation_ratio: 内存碎片率。计算公式为 used_memory_rss / used_memory。理想情况下在 1.0 - 1.5 之间。如果大于 1.5，说明内存碎片较多；如果远小于 1，说明 Redis 部分内存被交换到 Swap，通常意味着内存压力过大。\n\nmem_allocator: 编译时选用的内存分配器，通常是 jemalloc。\n\nlazyfree_pending_objects: 因执行 UNLINK 或带 ASYNC 选项的 FLUSH 命令而等待被后台线程释放的对象数量。\n\n4. Persistence (持久化信息)\n这部分用于监控 RDB 快照和 AOF 日志的状态。\n\nloading: 标志位，表示服务器是否正在启动时加载持久化文件。\n\nrdb_changes_since_last_save: 距离最后一次成功生成 RDB 后，发生变更的键次数。\n\nrdb_bgsave_in_progress: 标志位，表示当前是否正在执行 RDB 的 bgsave 操作。\n\nrdb_last_save_time: 最后一次成功 RDB 保存的 Unix 时间戳。\n\nrdb_last_bgsave_status: 最后一次 bgsave 的状态（ok 或 err）。\n\naof_enabled: 标志位，表示 AOF 是否已开启。\n\naof_rewrite_in_progress: 标志位，表示 AOF 重写是否正在进行中。重写过程可能会消耗大量磁盘 IO。\n\naof_last_bgrewrite_status: 最后一次 AOF 重写的状态。\n\n5. Stats (通用统计)\n这一块包含了命令执行、命中率、网络流量等核心统计数据。\n\ntotal_connections_received: 服务器启动以来接受的连接总数。\n\ntotal_commands_processed: 服务器启动以来处理的命令总数。\n\ninstantaneous_ops_per_sec: 每秒实时执行的命令数（QPS）。这是衡量当前负载的核心指标。\n\ntotal_net_input_bytes / total_net_output_bytes: 网络总输入/输出字节数。\n\ninstantaneous_input_kbps / instantaneous_output_kbps: 实时的网络输入/输出流量（KB/秒）。\n\nrejected_connections: 因超过 maxclients 限制而被拒绝的连接数。如果该值不为 0，说明连接数已达上限。\n\nkeyspace_hits / keyspace_misses: 查找键命中的次数和未命中的次数。结合两者可以算出缓存命中率（hits / (hits + misses)），这是衡量缓存效率的重要依据。\n\nexpired_keys: 被主动或被动过期机制清理掉的键总数。\n\nevicted_keys: 因 maxmemory 限制而被强制驱逐的键总数。如果这个值持续增长，说明内存压力极大。\n\n6. Replication (主从复制信息)\n对于使用主从架构的环境，这部分至关重要。\n\nrole: 当前实例的角色，是 master 还是 slave。\n\nconnected_slaves: 对于主节点，表示已连接的从节点数量。\n\nmaster_link_down_since: 对于从节点，如果与主节点的连接断开，这里记录断开持续的秒数。\n\nmaster_last_io_seconds_ago: 从节点距离上一次与主节点交互的秒数。用于判断主从复制是否存在延迟。\n\nslave_repl_offset: 从节点的复制偏移量。与主节点的 master_repl_offset 比较，可以精确计算复制延迟。\n\nrepl_backlog_active / repl_backlog_size: 复制积压缓冲区的状态和大小。缓冲区用于部分同步，如果太小可能导致网络抖动后触发全量同步。\n\n7. CPU (CPU 消耗统计)\nused_cpu_sys / used_cpu_user: Redis 服务器进程消耗的系统态 CPU 和用户态 CPU 总秒数（包括子进程）。\n\nused_cpu_sys_children / used_cpu_user_children: 后台进程（如 bgsave、aof rewrite）消耗的 CPU 秒数。\n\n8. Cluster (集群信息)\n仅当 Redis 运行在集群模式时才有意义。\n\ncluster_enabled: 标志位，指示集群模式是否已启用。\n\n如果启用了集群，执行 INFO cluster 或 CLUSTER INFO 可以看到更详细的信息，如 cluster_state（集群状态是否 ok）、cluster_slots_assigned（已分配的槽位数，正常应为 16384）等。\n\n9. Keyspace (数据库统计)\n这部分统计了每个逻辑数据库（DB 0-15）的键数量情况。\n\ndb0:keys=xxx,expires=yyy,avg_ttl=zzz: 表示数据库 0 中，一共有 keys 个键，其中 expires 个设置了过期时间，平均存活时间（TTL）为 avg_ttl。',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(22,1,'【查看有哪些客户端连接】redis-cli -a abc@123 -h 127.0.0.1 -p 6379 client list','redis-cli -a $PASSWORD -h $HOST -p $PORT  client list','【查看有哪些客户端连接】redis-cli -a abc@123 -h 127.0.0.1 -p 6379 client list','[\"基础\", \"常用\", \"查询\"]','redis-cli -a $PASSWORD -h $HOST -p $PORT  client list','CLIENT LIST 命令的输出是每行一个客户端，包含多个字段。以下是几个关键字段：\nid=123456 addr=127.0.0.1:54321 laddr=127.0.0.1:6379 fd=8 name= age=185 idle=0 flags=N db=0 sub=0 psub=0 multi=-1 qbuf=0 qbuf-free=0 argv-mem=0 multi-mem=0 obl=0 oll=0 omem=0 tot-mem=2064 events=r cmd=client|info user=default redir=-1 resp=2\n\n【核心字段说明】\n\n字段	说明\nid	客户端唯一标识符\naddr	客户端地址（IP:端口）\nladdr	服务器端地址（IP:端口）\nname	客户端名称（通过CLIENT SETNAME设置）\nage	连接已存在时间（秒）\nidle	连接空闲时间（秒）\nflags	客户端状态标志\ndb	当前选中的数据库ID\nsub	订阅的频道数量\npsub	订阅的模式数量\ncmd	最后执行的命令\nuser	认证使用的用户名\nresp	RESP协议版本\n\n【flags 标志说明】\n\n标志	说明\nN	普通客户端\nS	从库连接\nM	主库连接\nP	发布/订阅客户端\nB	阻塞命令等待中\nO	监视器模式客户端\nx	正在执行事务\nu	连接未阻塞\nA	需要关闭连接',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(23,1,'【查看配置参数】redis-cli -a abc@123 -h 127.0.0.1  -p 6379 config get  appendonly','redis-cli -a $PASSWORD -h $HOST -p $PORT   config get  [参数名称]','【查看配置参数】redis-cli -a abc@123 -h 127.0.0.1  -p 6379 config get  appendonly','[\"常用\"]','redis-cli -a $PASSWORD -h $HOST -p $PORT   config get  [参数名称]','在命令最后部分可以指定要获取的参数：\n参数模式	           说明	                               示例\n*	        获取所有配置（内容很多）               config get \"*\"\nrequirepass     获取认证密码(可能显示为空或 \"\")        config get requirepass\nmaxmemory       获取最大内存限制（字节）               config get maxmemory\nsave	        获取 RDB 持久化策略	             config get save\nport	        获取服务器监听端口	             config get port\n*max*           获取所有包含 “max” 字样的配置	     config get *max*    ',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(24,1,'【修改配置参数】redis-cli -a abc@123 -h 127.0.0.1  -p 6379 config set  appendonly 	yes	','redis-cli -a $PASSWORD -h $HOST -p $PORT   config set  [参数名字]  [参数值]','【修改配置参数】redis-cli -a abc@123 -h 127.0.0.1  -p 6379 config set  appendonly 	yes	','[\"常用\"]','redis-cli -a $PASSWORD -h $HOST -p $PORT   config set  [参数名字]  [参数值]','【常用配置参数说明】												\n参数名					   说明	                      示例\nappendonly			是否开启 AOF 持久化		config set appendonly yes\nmaxmemory			设置最大内存限制（字节）		config set maxmemory 1073741824（1GB）\nrequirepass			设置认证密码			config set requirepass myNewPass123\ntimeout				客户端空闲关闭超时（秒）		config set timeout 300\ndatabases			设置数据库总数（需重启生效）	config set databases 16\nslowlog-max-len			设置慢查询最大记录条数		config set slowlog-max-len 128\nappendfsync			设置 AOF 同步策略		config set appendfsync everysec\nrepl-timeout			主从复制超时时间（秒）		config set repl-timeout 60\n',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(25,1,'【配置参数持久化写入到配置文件】redis-cli -a abc@123 -h 127.0.0.1  -p 6379 config rewrite','redis-cli -a $PASSWORD -h $HOST -p $PORT   config rewrite','【配置参数持久化写入到配置文件】redis-cli -a abc@123 -h 127.0.0.1  -p 6379 config rewrite','[\"常用\"]','redis-cli -a $PASSWORD -h $HOST -p $PORT   config rewrite','',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(26,1,'【停止进程前强制执行RDB持久化】redis-cli -a abc@123 -h 127.0.0.1  -p 6379 shutdown save','redis-cli -a $PASSWORD -h $HOST -p $PORT    shutdown save','【停止进程前强制执行RDB持久化】redis-cli -a abc@123 -h 127.0.0.1  -p 6379 shutdown save','[\"基础\", \"常用\"]','redis-cli -a $PASSWORD -h $HOST -p $PORT    shutdown save','\n【SHUTDOWN 所有参数详解】 \n参数	说明	                     数据保存	       阻塞行为	          适用场景\n无参数	默认关闭模式	         根据配置自动保存     等待保存完成	          常规关闭\nSAVE	关闭前强制执行RDB持久化      强制保存	     阻塞直到保存完成	 确保数据不丢失\nNOSAVE	关闭前不保存数据	            不保存	      立即关闭	        快速重启（可丢数据）\nABORT	取消正在进行的关闭	    —	                非阻塞	       取消已触发的 SHUTDOWN',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(27,1,'【手动故障转移】redis-cli -h 127.0.0.1  -p 26379  SENTINEL FAILOVER mymaster','redis-cli  -h $HOST -p $SENTINEL_PORT   SENTINEL FAILOVER mymaster','【手动故障转移】redis-cli -h 127.0.0.1  -p 26379  SENTINEL FAILOVER mymaster','[\"操作\"]','redis-cli  -h $HOST -p $SENTINEL_PORT   SENTINEL FAILOVER mymaster','【命令作用说明】\n说明项	             详细解释\n核心功能	         强制对指定主节点执行故障转移（Failover），即使主节点看似正常\n执行者               Redis Sentinel（哨兵）节点，而非 Redis 主从节点\n使用场景	         手动切换主从、计划内维护、主节点性能问题、强制重置主从关系\n工作方式	         Sentinel 会忽略主节点的健康状态，直接选举一个新的从库晋升为主库\n\nSENTINEL FAILOVER 	 Sentinel 命令：强制执行故障转移	\nmymaster	         要执行故障转移的主节点名称（在 sentinel.conf 中配置）	  \n',NULL,2,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(28,1,'【刷新哨兵状态】redis-cli -h 127.0.0.1  -p 26379  SENTINEL RESET mymaster','redis-cli  -h $HOST -p $SENTINEL_PORT   SENTINEL RESET mymaster','【刷新哨兵状态】redis-cli -h 127.0.0.1  -p 26379  SENTINEL RESET mymaster','[\"操作\"]','redis-cli  -h $HOST -p $SENTINEL_PORT   SENTINEL RESET mymaster','执行后哨兵会：\n清除 mymaster 主节点的故障转移历史记录\n清除所有从节点、其他哨兵节点的旧状态、旧地址、旧故障信息\n重新根据配置文件重新发现、重新监控 mymaster 主节点及其从节点、其他哨兵\n重置后哨兵会重新建立拓扑、重新选举、重新判断节点状态\n\nSENTINEL RESET	哨兵的重置命令\nmymaster	 主节点名称 (在 sentinel 配置文件中 sentinel monitor mymaster ... 定义的)',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(29,1,'【查看集群状态】 redis-cli -a abc@123 -h 127.0.0.1  -p 6379  cluster info','redis-cli -a $PASSWORD -h $HOST -p $PORT   cluster info','【查看集群状态】 redis-cli -a abc@123 -h 127.0.0.1  -p 6379  cluster info','[\"查询\", \"集群\"]','redis-cli -a $PASSWORD -h $HOST -p $PORT   cluster info','CLUSTER INFO 命令输出详解\n执行后会返回集群的关键状态信息，每个字段含义如下：\n\n字段	                                    说明	                正常值示例\ncluster_state	                    集群当前状态          	     ok (正常) / fail (失败)\ncluster_slots_assigned	            已分配的槽位总数     	     16384 (全部槽位)\ncluster_slots_ok	            正常工作的槽位数	             16384\ncluster_slots_pfail	            可能失败（PFAIL）的槽位数          0\ncluster_slots_fail	            已确认失败（FAIL）的槽位数         0\ncluster_known_nodes	            集群中已知的节点总数	   	     3 / 6 等\ncluster_size	                    集群主节点数量		     3\ncluster_current_epoch	            当前集群配置版本号		     6\ncluster_my_epoch	            当前节点的配置版本号		     3\ncluster_stats_messages_sent	    发送的集群消息总数		     12345\ncluster_stats_messages_received	    接收的集群消息总数		     12340\ncluster_stats_messages_ping_sent    发送的 PING 消息数	             12345\ncluster_stats_messages_pong_sent	发送的 PONG 消息数	     12345 \ncluster_stats_messages_ping_received	接收的 PING 消息数	     12345\ncluster_stats_messages_pong_received	接收的 PONG 消息数	     12345',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(30,1,'【查看集群节点信息】 redis-cli -a abc@123 -h 127.0.0.1  -p 6379   cluster nodes','redis-cli -a $PASSWORD -h $HOST -p $PORT    cluster nodes','【查看集群节点信息】 redis-cli -a abc@123 -h 127.0.0.1  -p 6379   cluster nodes','[\"查询\", \"集群\"]','redis-cli -a $PASSWORD -h $HOST -p $PORT    cluster nodes','字段说明\n字段	        说明	                                           示例\nnode-id	        节点唯一标识符（40位十六进制字符串）	d6b9a7f8e3c2a1b4c5d6e7f8a9b0c1d2e3f4a5b6\nip:port@cport	节点地址：<IP>:<数据端口>@<集群总线端口>	 10.0.0.1:6379@16379\nflags	        节点角色和状态标志	                   master、slave、myself、fail 等\nmaster-id	如果是从节点，显示主节点的 ID；主节点则显示 -	  d6b9a7f8... 或 -\nping-sent	上次发送 ping 的时间戳（毫秒），0 表示刚启动	   0、1234567890\npong-recv	上次收到 pong 的时间戳（毫秒）	                   1234567890\nconfig-epoch    节点配置版本号（用于故障转移选举）                   	3、12\nlink-state	集群总线连接状态	                           connected、disconnected\nslot-range	主节点负责的槽位范围（从节点显示为空）	    0-5460、[5461-10922]\n\n\nFlags       标志详解\n标志	    含义\nmaster	    主节点\nslave	    从节点\nmyself	    当前连接的节点\nfail	    节点处于 FAIL 状态\npfail	    节点处于 PFAIL 状态（疑似下线）\nhandshake   正在进行握手\nnoaddr	    节点地址未知\nnoflags	    无特殊标志',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(31,1,'【慢日志查询】 redis-cli -a abc@123 -h 127.0.0.1  -p 6379   slowlog get 5','redis-cli -a $PASSWORD -h $HOST -p $PORT   slowlog get [N]','【慢日志查询】 redis-cli -a abc@123 -h 127.0.0.1  -p 6379   slowlog get 5','[\"查询\"]','redis-cli -a $PASSWORD -h $HOST -p $PORT   slowlog get [N]','# 返回最新的N条慢查询记录。如果N省略，返回10条\n#设置慢查询阈值，单位是微秒。如果执行命令的时间超过这个阈值，就会被记录到慢查询日志。默认值是10000微秒（即10毫秒）。如果设置为-1，将禁用慢查询日志.\n#设置慢查询日志的最大长度。如果新的慢查询记录导致日志长度超过这个值，最旧的记录将被删除。默认值是128.\n1) 1) (integer) 1234567        # 日志唯一ID（自增）\n   2) (integer) 1703123456789  # 命令执行时间戳（微秒）\n   3) (integer) 15000          # 命令执行耗时（微秒，1秒=1,000,000微秒）\n   4) 1) \"SET\"                 # 执行的命令及参数\n      2) \"user:1001\"\n      3) \"some_value\"\n   5) \"127.0.0.1:54321\"        # 客户端地址（Redis 4.0+）\n   6) \"myuser\"                 # 用户名（Redis 6.0+，启用ACL时）\n\n\ndate -d @1703123456789   转换为可读时间',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(32,1,'【集群批量执行命令】 redis-cli -a abc@123 --cluster call  127.0.0.1:6379 info ','redis-cli -a $PASSWORD --cluster call    $HOST:$PORT   【命令】','【集群批量执行命令】 redis-cli -a abc@123 --cluster call  127.0.0.1:6379 info ','[\"集群\"]','redis-cli -a $PASSWORD --cluster call    $HOST:$PORT   【命令】','参数说明\n参数	         说明	                         示例\n-a	        Redis 认证密码	               -a abc123\n--cluster call	集群模式下在所有节点执行命令	固定参数\n<host>:<port>	集群中任意一个节点的地址和端口	127.0.0.1:6379\n<command>	要执行的 Redis 命令	       INFO SERVER\n\n',NULL,1,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(33,17,'【启动服务】','rabbitmq-server  -detached','【启动服务】','[\"重启\"]','rabbitmq-server  -detached','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(34,17,'【停止服务】','rabbitmqctl stop','【停止服务】','[\"重启\"]','rabbitmqctl stop','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(35,17,'【启动应用】','rabbitmqctl start_app','【启动应用】','[\"重启\"]','rabbitmqctl start_app','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(36,17,'【停止应用】','rabbitmqctl stop_app','【停止应用】','[\"重启\"]','rabbitmqctl stop_app','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(37,17,'查看集群状态','rabbitmqctl cluster_status','查看集群状态','[\"查询\"]','rabbitmqctl cluster_status','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(38,17,'【查看用户列表】','rabbitmqctl list_users','【查看用户列表】','[\"查询\"]','rabbitmqctl list_users','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(39,17,'【修改密码】','rabbitmqctl change_password $userName $newPassword','【修改密码】','[\"操作\"]','rabbitmqctl change_password $userName $newPassword','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(40,17,'【删除用户】','rabbitmqctl delete_user userName','【删除用户】','[\"操作\"]','rabbitmqctl delete_user userName','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(41,15,'【启动服务】','/app/kafka/kafka_home/bin/kafka-server-start.sh -daemon /app/kafka/kafka_home/config/kafkaserver.properties','【启动服务】','[\"基础\", \"操作\"]','/app/kafka/kafka_home/bin/kafka-server-start.sh -daemon /app/kafka/kafka_home/config/kafkaserver.properties','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(42,15,'【停止服务】','/app/kafka/kafka_home/bin/kafka-server-stop.sh','【停止服务】','[\"基础\", \"操作\"]','/app/kafka/kafka_home/bin/kafka-server-stop.sh','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(43,15,'【查看top详情】','/app/kafka/kafka_home/bin/kafka-topics.sh --bootstrap-server 127.0.0.1:9092     --describe ','【查看top详情】','[\"查询\"]','/app/kafka/kafka_home/bin/kafka-topics.sh --bootstrap-server 127.0.0.1:9092     --describe ','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(44,15,'【Leader重平衡】','/app/kafka/kafka_home/bin/kafka-leader-election.sh --bootstrap-server 127.0.0.1:9092    --election-type preferred --all-topic-partitions','【Leader重平衡】','[\"操作\"]','/app/kafka/kafka_home/bin/kafka-leader-election.sh --bootstrap-server 127.0.0.1:9092    --election-type preferred --all-topic-partitions','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(45,15,'【topic 加副本】','/app/kafka/kafka_home/bin/kafka-reassign-partitions.sh --bootstrap-server  127.0.0.1:9092  --execute --reassignment-json-file  middletest2.json','【topic 加副本】','[\"操作\"]','/app/kafka/kafka_home/bin/kafka-reassign-partitions.sh --bootstrap-server  127.0.0.1:9092  --execute --reassignment-json-file  middletest2.json','',NULL,0,'2026-06-08 13:02:53','2026-06-08 14:26:40'),(46,15,'【查看消费者组my_group消费情况】','kafka-consumer-groups.sh   --bootstrap-server 127.0.0.1:9092   --describe   --group my_group','【查看消费者组my_group消费情况】','[\"查询\"]','kafka-consumer-groups.sh   --bootstrap-server 127.0.0.1:9092   --describe   --group my_group','',NULL,0,'20